using System.Collections.Generic;
using UnityEngine;

[RequireComponent(typeof(Rigidbody2D), typeof(CapsuleCollider2D), typeof(Animator))]
public class PlayerMotor2D : MonoBehaviour
{
    [Header("Ground Check")]
    public LayerMask groundLayer;

    [Tooltip("Margem extra abaixo do capsule para detectar o chão.")]
    [SerializeField] private float groundExtraHeight = 0.06f;

    [Tooltip("Largura do ground check como percent do capsule width (0.8 = 80%).")]
    [Range(0.3f, 1f)]
    [SerializeField] private float groundWidthFactor = 0.85f;

    [Tooltip("Altura do ground check (pequena).")]
    [SerializeField] private float groundCheckHeight = 0.10f;

    [Header("Gelo / Terreno Escorregadio (P8)")]
    [Tooltip("Camadas tratadas como 'gelo' (ex: lagos congelados). Em cima delas, o atrito horizontal (accel/decel/skidBrake) é multiplicado por 'AnimalFormData.iceSlideFactor' — Pinguim desliza muito, a maioria das formas (1 = padrão) não é afectada. Vazio = sem efeito de gelo no jogo.")]
    public LayerMask iceLayer;

    [Header("Vento (Tarefa #6 — WindZone)")]
    [Tooltip("Escala geral da força horizontal do vento sobre o player (dividida pelo peso da forma — AnimalFormData.weightMultiplier). 1 = usa directamente 'windStrength' da zona.")]
    public float windHorizontalForce = 1f;

    [Tooltip("Multiplicador extra aplicado à força horizontal do vento quando o player está a andar NO MESMO sentido do vento (favorável — ganha velocidade extra, inclusive em saltos).")]
    public float windTailwindMultiplier = 1.5f;

    [Tooltip("Multiplicador aplicado à força horizontal do vento quando o player está a andar CONTRA o vento (resistência — trava o avanço).")]
    public float windHeadwindMultiplier = 1f;

    [Tooltip("Escala geral da força vertical do vento sobre o player (dividida pelo peso da forma). Vento para cima reduz a gravidade efectiva (sobe/cai mais devagar); vento para baixo aumenta-a (cai/salta mais rápido e baixo).")]
    public float windVerticalForce = 1f;

    [Header("State (read only)")]
    [SerializeField] private bool isGrounded;
    [SerializeField] private bool isDashing;
    [SerializeField] private bool isOnIce;
    [SerializeField] private int facingSign = 1;

    public bool IsGrounded => isGrounded;
    public bool IsDashing => isDashing;

    /// <summary>
    /// Conjunto de "donos" que estão actualmente a bloquear o movimento
    /// (armadilha, stun, dash, escalar, balanço, língua, escudo, diálogo,
    /// morte, etc.). Cada chamador de <see cref="SetMovementLocked"/> passa-se
    /// a si próprio como "source": assim um sistema a desbloquear (false) só
    /// remove o SEU próprio bloqueio, e o movimento só fica livre quando
    /// nenhum sistema o estiver a reter. Antes, um único bool partilhado fazia
    /// com que, por ex., o fim do stun (PlayerCombat) libertasse o player
    /// mesmo com uma armadilha (EnemyAttackController) ainda activa.
    /// </summary>
    private readonly Dictionary<object, int> movementLocks = new Dictionary<object, int>();

    public bool MovementLocked => movementLocks.Count > 0;

    /// <summary>true se o ground check actual está sobre uma camada de 'iceLayer' (P8).</summary>
    public bool IsOnIce => isOnIce;
    public int FacingSign => facingSign;

    public Rigidbody2D RB { get; private set; }
    public CapsuleCollider2D Capsule { get; private set; }
    public Animator Anim { get; private set; }

    // Current form stats
    private AnimalFormData form;

    // Input (agora vem de fora)
    private float moveX;
    private bool jumpPressedThisFrame;
    private bool jumpReleasedThisFrame;

    // Jump helpers
    private float coyoteTimer;
    private float jumpBufferTimer;
    private int jumpsLeft;

    // Run ramp / skid
    private float sameDirTimer;
    private int lastMoveDir = 1;
    private bool isSkidding;

    // Jump requests para executar no FixedUpdate
    private bool jumpRequest;
    private bool jumpCutRequest;

    // Cached ground check values (recalculado ao mudar forma)
    private Vector2 groundCheckSize;
    private Vector2 groundCheckWorldPos;

    // Movimento aquático (Tarefa #14): enquanto activo, este módulo controla
    // toda a movimentação (natação, correntes, impulso, investida da Orca).
    private WaterMotor2D waterMotor;

    // Tarefa #28 — fonte do SkidGripMultiplier (buff "Raiz de Aderência").
    private PlayerCombat combat;

    // Tarefa #7 — Guepardo: SprintAbility.IsSprinting determina se correntes
    // de vento "fracas" (WindZone.isSmallCurrent) são ignoradas.
    private SprintAbility sprintAbility;

    private void Awake()
    {
        RB = GetComponent<Rigidbody2D>();
        Capsule = GetComponent<CapsuleCollider2D>();
        Anim = GetComponent<Animator>();
        combat = GetComponent<PlayerCombat>();
        waterMotor = GetComponent<WaterMotor2D>();
        sprintAbility = GetComponent<SprintAbility>();

        if (facingSign == 0) facingSign = 1; // <- FIX

        RecalculateGroundCheck();
    }

    // ---------------- Public API (Input System friendly) ----------------

    public void SetMoveX(float x)
    {
        moveX = Mathf.Clamp(x, -1f, 1f);

        if (Mathf.Abs(moveX) > 0.01f)
            facingSign = moveX > 0f ? 1 : -1;
    }

    public void QueueJumpPressed()
    {
        jumpPressedThisFrame = true;
    }

    public void QueueJumpReleased()
    {
        jumpReleasedThisFrame = true;
    }

    public void ApplyForm(AnimalFormData newForm)
    {
        form = newForm;

        // Reset estados para não herdar comportamento estranho
        ResetMotionStateForNewForm();

        // Jumps
        jumpsLeft = form != null ? form.extraJumps : 0;

        if (form != null)
        {
            // Gravidade por animal
            if (form.gravityScale > 0f)
                RB.gravityScale = form.gravityScale;

            // Preserva a posição dos "pés" (base do CapsuleCollider2D) ao
            // trocar de forma: cada animal tem colliderSize/colliderOffset
            // próprios, por isso a base do collider novo nem sempre coincide
            // com a do antigo — sem este ajuste, animais grandes podiam
            // nascer enterrados no chão (ou pequenos a flutuar) ao
            // transformar.
            float oldBottomY = Capsule.offset.y - Capsule.size.y * 0.5f;

            // Collider (tamanho/offset definidos pela forma)
            Capsule.size = form.colliderSize;
            Capsule.offset = form.colliderOffset;

            float newBottomY = Capsule.offset.y - Capsule.size.y * 0.5f;
            float deltaY = oldBottomY - newBottomY;

            if (Mathf.Abs(deltaY) > 0.0001f)
                RB.position += new Vector2(0f, deltaY);
        }

        // Recalcula ground check com base no novo collider (ou override da forma)
        RecalculateGroundCheck();
    }

    public void SetDashing(bool dashing) => isDashing = dashing;

    /// <summary>
    /// Bloqueia ("locked" = true) ou liberta ("locked" = false) o movimento em
    /// nome de "source" (passa normalmente "this" do script que está a pedir
    /// o bloqueio — armadilha, stun, dash, escalar, balanço, língua, escudo,
    /// diálogo/cutscene, morte, etc.). <see cref="MovementLocked"/> só fica
    /// false quando TODOS os "sources" activos já tiverem chamado
    /// SetMovementLocked(false, ...) — ver comentário em
    /// <see cref="movementLocks"/>.
    /// </summary>
    public void SetMovementLocked(bool locked, object source)
    {
        if (source == null) source = this;

        if (locked)
        {
            movementLocks.TryGetValue(source, out int count);
            movementLocks[source] = count + 1;
        }
        else if (movementLocks.TryGetValue(source, out int count))
        {
            if (count <= 1) movementLocks.Remove(source);
            else movementLocks[source] = count - 1;
        }
    }

    /// <summary>
    /// Remove todos os locks de movimento activos (usado ao carregar um save ou
    /// transitar de cena — garante que armadilhas, stuns e outros locks de frames
    /// anteriores não ficam presos indefinidamente).
    /// </summary>
    public void ClearAllMovementLocks()
    {
        movementLocks.Clear();
    }

    /// <summary>
    /// Multiplicador de velocidade horizontal (aplicado a baseSpeed/maxSpeed).
    /// Usado por SprintAbility (P5). 1 = normal. Reposto a 1 ao mudar de forma.
    /// </summary>
    public void SetSpeedMultiplier(float multiplier) => speedMultiplier = Mathf.Max(0.1f, multiplier);

    private float speedMultiplier = 1f;

    /// <summary>
    /// Tarefa #6 — Vento: aplicado por WindZone.OnTriggerStay2D (uma vez por
    /// FixedUpdate enquanto o player estiver dentro da zona), com
    /// 'wind' = direcção normalizada da zona * windStrength.
    ///
    /// Horizontal: parado = desloca-se (mais quanto mais leve for a forma,
    /// via weightMultiplier); a andar A FAVOR do vento = ganha velocidade
    /// extra (windTailwindMultiplier); a andar CONTRA = resistência
    /// (windHeadwindMultiplier trava o avanço).
    ///
    /// Vertical: vento para cima soma aceleração ascendente (reduz a
    /// gravidade efectiva — sobe/cai mais devagar, salta mais alto/longe);
    /// vento para baixo soma aceleração descendente (cai/salta mais rápido e
    /// baixo). Objectos/formas muito leves com vento forte para cima podem
    /// "flutuar" (aceleração ascendente supera a gravidade).
    ///
    /// Aplica-se mesmo com MovementLocked (tal como as correntes de água —
    /// ver WaterCurrentZone/WaterMotor2D.AddCurrentForce).
    /// </summary>
    public void ApplyWind(Vector2 wind, bool isSmallCurrent = false)
    {
        if (form == null) return;

        // Guepardo (Tarefa #7): a sprintar, "quebra" correntes de vento fracas
        // (WindZone.isSmallCurrent) — ignora-as por completo.
        if (isSmallCurrent && form.canBreakSmallWindCurrents && sprintAbility != null && sprintAbility.IsSprinting)
            return;

        float weight = Mathf.Max(0.05f, form.weightMultiplier);
        float dt = Time.fixedDeltaTime;

        if (Mathf.Abs(wind.x) > 0.0001f)
        {
            int moveDir = (moveX > 0.01f) ? 1 : (moveX < -0.01f ? -1 : 0);
            int windDir = wind.x > 0f ? 1 : -1;

            float horizontalAccel = wind.x / weight * windHorizontalForce;

            if (moveDir != 0)
                horizontalAccel *= (moveDir == windDir) ? windTailwindMultiplier : windHeadwindMultiplier;

            RB.linearVelocity += new Vector2(horizontalAccel * dt, 0f);
        }

        if (Mathf.Abs(wind.y) > 0.0001f)
        {
            float verticalAccel = wind.y / weight * windVerticalForce;
            RB.linearVelocity += new Vector2(0f, verticalAccel * dt);
        }
    }

    // ---------------- Unity loop ----------------

    private void Update()
    {
        // Se não tem form ainda, só actualiza animação
        if (form == null)
        {
            UpdateAnimatorParams();
            jumpPressedThisFrame = false;
            jumpReleasedThisFrame = false;
            return;
        }

        // Ground check (frame)
        UpdateGrounded();

        // Coyote
        if (isGrounded)
            coyoteTimer = form.coyoteTime;
        else
            coyoteTimer -= Time.deltaTime;

        // Jump buffer
        if (jumpPressedThisFrame)
            jumpBufferTimer = form.jumpBuffer;
        else
            jumpBufferTimer -= Time.deltaTime;

        // Reset extra jumps ao tocar no chão
        if (isGrounded)
            jumpsLeft = form.extraJumps;

        UpdateFacing();
        UpdateRunTimers();

        // Marcar pedidos de jump (executa no FixedUpdate)
        PrepareJumpRequests();

        UpdateAnimatorParams();

        // consumir flags 'this frame'
        jumpPressedThisFrame = false;
        jumpReleasedThisFrame = false;
    }

    private void FixedUpdate()
    {
        if (form == null) return;
        if (MovementLocked) return;

        // WaterMotor2D assume o controlo total do movimento (natação,
        // correntes, impulso aquático, investida da Orca) enquanto a forma
        // for aquática e o player estiver dentro de água. Como ExecuteJumpRequests()
        // não corre aqui, descartamos qualquer pedido de salto pendente — sem
        // isto, um "jumpRequest" preparado em Update() enquanto a nadar ficava
        // pendente e disparava um salto inesperado no primeiro FixedUpdate
        // depois de saír de água.
        if (waterMotor != null && waterMotor.IsActive)
        {
            DiscardPendingJumpRequests();
            return;
        }

        // SwimOnly fora de água (ex.: encalhado): sem movimento horizontal
        // activo, só desacelera. WaterMotor2D trata de tudo o resto na água.
        if (form.movementMode == MovementMode.SwimOnly)
        {
            ApplyDecelIfNoInput();
            return;
        }

        HandleHorizontalMovement();
        ApplyDecelIfNoInput();

        ExecuteJumpRequests();
    }

    // ---------------- Ground ----------------

    /// <summary>
    /// Recalcula o tamanho/posição da caixa de ground check com base no
    /// CapsuleCollider2D actual (tamanho/offset). Deve ser chamado sempre que
    /// algo redimensionar o Capsule fora de ApplyForm (ex.: CrawlAbility ao
    /// entrar/saír do modo de rastejar).
    /// </summary>
    public void RecalculateGroundCheck()
    {
        if (form != null && form.overrideGroundCheck)
        {
            // Forma define o próprio tamanho de ground check
            groundCheckSize = form.groundCheckSize;
            return;
        }

        // Ground check ' baseado no CapsuleCollider actual (tamanho/offset)
        float width = Capsule.size.x * groundWidthFactor;
        groundCheckSize = new Vector2(width, groundCheckHeight);
    }

    private void UpdateGrounded()
    {
        if (form != null && form.overrideGroundCheck)
        {
            groundCheckWorldPos = (Vector2)transform.position + form.groundCheckOffset;
        }
        else
        {
            // posição do bottom do capsule no mundo
            Vector2 pos = (Vector2)transform.position + Capsule.offset;

            // bottomY = centro - metade altura
            float bottomY = pos.y - (Capsule.size.y * 0.5f);

            // coloca a caixa um pouco abaixo do capsule
            groundCheckWorldPos = new Vector2(pos.x, bottomY - groundExtraHeight);
        }

        isGrounded = Physics2D.OverlapBox(groundCheckWorldPos, groundCheckSize, 0f, groundLayer);

        // Gelo (P8): mesma caixa do ground check, contra 'iceLayer'.
        isOnIce = iceLayer.value != 0 && Physics2D.OverlapBox(groundCheckWorldPos, groundCheckSize, 0f, iceLayer);
    }

    /// <summary>Multiplicador de atrito (accel/decel/skidBrake) da forma actual: iceSlideFactor se estiver em cima de 'iceLayer', senão 1 (sem efeito).</summary>
    private float CurrentIceFactor()
    {
        return isOnIce ? Mathf.Clamp(form.iceSlideFactor, 0.05f, 1f) : 1f;
    }

    // ---------------- Facing / Run timers ----------------

    private void UpdateFacing()
    {
        // Preferência: se há input, vira com o input. Senão, usa velocidade.
        if (Mathf.Abs(moveX) > 0.01f)
            facingSign = moveX > 0f ? 1 : -1;
        else if (RB.linearVelocity.x > 0.2f)
            facingSign = 1;
        else if (RB.linearVelocity.x < -0.2f)
            facingSign = -1;
    }

    private void UpdateRunTimers()
    {
        int dir = (moveX > 0.01f) ? 1 : (moveX < -0.01f ? -1 : 0);

        if (dir == 0)
        {
            sameDirTimer = Mathf.Max(0f, sameDirTimer - Time.deltaTime * 2f);
            isSkidding = false;
            return;
        }

        if (dir != lastMoveDir)
        {
            // Skid se estiver rápido demais
            if (Mathf.Abs(RB.linearVelocity.x) >= form.turnLockSpeed)
                isSkidding = true;
            else
                isSkidding = false;

            sameDirTimer = 0f;
            lastMoveDir = dir;
        }
        else
        {
            sameDirTimer += Time.deltaTime;
        }
    }

    // ---------------- Horizontal movement ----------------

    private void HandleHorizontalMovement()
    {
        float vx = RB.linearVelocity.x;
        int inputDir = (moveX > 0.01f) ? 1 : (moveX < -0.01f ? -1 : 0);
        if (inputDir == 0) return;

        float iceFactor = CurrentIceFactor();

        // Skid (Mario-like) — no gelo, o skidBrake é reduzido (derrapa mais).
        if (isSkidding)
        {
            // Tarefa #28 — "Raiz de Aderência" reduz a derrapagem temporariamente (>= 1).
            float gripMultiplier = combat != null ? combat.SkidGripMultiplier : 1f;
            float newVx = Mathf.MoveTowards(vx, 0f, form.skidBrake * iceFactor * gripMultiplier * Time.fixedDeltaTime);
            RB.linearVelocity = new Vector2(newVx, RB.linearVelocity.y);

            if (Mathf.Abs(newVx) <= form.turnLockSpeed * 0.35f)
                isSkidding = false;

            return;
        }

        // Ramp para maxSpeed (com multiplicador de Sprint — P5)
        float t = (form.timeToMaxSpeed <= 0.01f) ? 1f : Mathf.Clamp01(sameDirTimer / form.timeToMaxSpeed);
        float targetSpeed = Mathf.Lerp(form.baseSpeed, form.maxSpeed, t) * speedMultiplier * inputDir;

        float maxSpeed = form.maxSpeed * speedMultiplier;

        // No gelo, ganhar/perder velocidade fica mais lento (accel reduzido — escorrega).
        float newVX = Mathf.MoveTowards(vx, targetSpeed, form.accel * iceFactor * Time.fixedDeltaTime);
        newVX = Mathf.Clamp(newVX, -maxSpeed, maxSpeed);

        RB.linearVelocity = new Vector2(newVX, RB.linearVelocity.y);
    }

    private void ApplyDecelIfNoInput()
    {
        if (Mathf.Abs(moveX) > 0.01f) return;

        // No gelo, sem input o player continua a deslizar (decel reduzido pelo iceSlideFactor da forma).
        float decel = form.decel * CurrentIceFactor();

        float vx = RB.linearVelocity.x;
        float newVX = Mathf.MoveTowards(vx, 0f, decel * Time.fixedDeltaTime);
        RB.linearVelocity = new Vector2(newVX, RB.linearVelocity.y);
    }

    // ---------------- Jump ----------------

    private void PrepareJumpRequests()
    {
        if (form == null || !form.canJump) return;

        bool canGroundJump = (jumpBufferTimer > 0f && coyoteTimer > 0f);

        // Tarefa #5: para formas com canGlide, o botão de Saltar no ar é
        // reservado para activar o Glide (AbilityRouter.OnJumpPressedAirborne)
        // — não consome "jumpsLeft" nem aplica impulso de salto extra.
        bool canExtraJump = (jumpPressedThisFrame && !isGrounded && jumpsLeft > 0 && !form.canGlide);

        if (canGroundJump)
        {
            jumpRequest = true;
            // consumimos os timers j' aqui (responsivo)
            jumpBufferTimer = 0f;
            coyoteTimer = 0f;
        }
        else if (canExtraJump)
        {
            jumpsLeft--;
            jumpRequest = true;
        }

        // Jump cut (soltar botão corta pulo) é aplica no FixedUpdate
        if (jumpReleasedThisFrame && RB.linearVelocity.y > 0f)
        {
            jumpCutRequest = true;
        }
    }

    /// <summary>Descarta pedidos de salto pendentes (ver chamada em FixedUpdate enquanto WaterMotor2D.IsActive).</summary>
    private void DiscardPendingJumpRequests()
    {
        jumpRequest = false;
        jumpCutRequest = false;
    }

    private void ExecuteJumpRequests()
    {
        if (jumpRequest)
        {
            // zera Y antes pra consistência
            RB.linearVelocity = new Vector2(RB.linearVelocity.x, 0f);
            RB.AddForce(Vector2.up * form.jumpForce, ForceMode2D.Impulse);
            jumpRequest = false;
        }

        if (jumpCutRequest)
        {
            // corta pulo só se ainda estiver a subir
            if (RB.linearVelocity.y > 0f)
                RB.linearVelocity = new Vector2(RB.linearVelocity.x, RB.linearVelocity.y * form.jumpCutMultiplier);

            jumpCutRequest = false;
        }
    }

    // ---------------- Animator ----------------

    private void UpdateAnimatorParams()
    {
        if (Anim == null) return;

        Anim.SetFloat("Speed", Mathf.Abs(RB.linearVelocity.x));
        Anim.SetBool("IsGrounded", isGrounded);
        Anim.SetBool("IsDashing", isDashing);
        Anim.SetFloat("YVel", RB.linearVelocity.y);

        // Pré-programado (mesmo que não uses agora)
        Anim.SetInteger("FacingSign", facingSign);
        Anim.SetBool("IsSkidding", isSkidding);

        // Gelo (P8) — para VFX/animação de deslize (ex: Pinguim de barriga).
        Anim.SetBool("IsOnIce", isOnIce);
    }

    // ---------------- Utils ----------------

    private void ResetMotionStateForNewForm()
    {
        // Reset multiplicador de Sprint (P5)
        speedMultiplier = 1f;

        // Reset timers
        coyoteTimer = 0f;
        jumpBufferTimer = 0f;

        // Reset corrida / skid
        sameDirTimer = 0f;
        isSkidding = false;
        lastMoveDir = facingSign;

        // Cancel requests
        jumpRequest = false;
        jumpCutRequest = false;

        // Input transient flags
        jumpPressedThisFrame = false;
        jumpReleasedThisFrame = false;
    }

    private void OnDrawGizmosSelected()
    {
        if (Capsule == null) return;

        Gizmos.color = Color.yellow;

        Vector2 gPos;
        Vector2 size;

        if (form != null && form.overrideGroundCheck)
        {
            gPos = (Vector2)transform.position + form.groundCheckOffset;
            size = form.groundCheckSize;
        }
        else
        {
            // desenha a caixa de ground check como está calculada
            Vector2 pos = (Vector2)transform.position + Capsule.offset;
            float bottomY = pos.y - (Capsule.size.y * 0.5f);
            gPos = new Vector2(pos.x, bottomY - groundExtraHeight);
            size = new Vector2(Capsule.size.x * groundWidthFactor, groundCheckHeight);
        }

        Gizmos.DrawWireCube(gPos, size);
    }
}
